import prometheus_client
from prometheus_client import Summary

# Define a summary metric for HTTP requests with labels for user_id, session_id, and full request path
http_requests = Summary(
    'http_requests',
    'HTTP requests',
    ['user_id', 'session_id', 'full_request_path']
)

# Define a function to track HTTP requests with the defined labels
def track_http_request(user_id, session_id, full_request_path):
    # Increment the counter for this user-path combination
    http_requests.labels(user_id=user_id, session_id=session_id, full_request_path=full_request_path).inc()

# Use the track_http_request function to track HTTP requests with different labels
track_http_request('1234', 'abcdefg', '/api/v1/users')
track_http_request('5678', 'hijklmn', '/api/v1/products')